def solve(s: String, order: Array[Long], k: Long): Long = {
    val n = s.length
    var left = 0L
    var right = n - 1
    var answer = -1L

    while (left <= right) {
        val mid = left + (right - left) / 2
        val modified = s.toCharArray
        for (i <- 0 to mid.toInt) {
            modified(order(i).toInt) = '*'
        }

        var count = 0L
        var lastStar = -1L
        for (i <- 0 until n) {
            if (modified(i) == '*') {
                lastStar = i
            }
            if (lastStar != -1) {
                count += lastStar + 1
            }
            if (count >= k) {
                answer = mid
                right = mid - 1
                return answer
            }
        }

        if (count < k) {
            left = mid + 1
        } else {
            answer = mid
            right = mid - 1
        }
    }

    answer
}
